mapper.select:
select

from bms_order_detail_tb

    and order_num=#{orderNum,jdbcType=VARCHAR}
    and order_detail_num=#{orderDetailNum,jdbcType=VARCHAR}
    and project_code=#{projectCode,jdbcType=VARCHAR}
    and supplier_code=#{supplierCode,jdbcType=VARCHAR}
    and
        contact_user_telephone=#{contactUserTelephone,jdbcType=VARCHAR}

    and contact_user_name=#{contactUserName,jdbcType=VARCHAR}
    and brand_code=#{brandCode,jdbcType=VARCHAR}
    and product_name=#{productName,jdbcType=VARCHAR}
    and product_specs=#{productSpecs,jdbcType=VARCHAR}
    and product_out_code=#{productOutCode,jdbcType=VARCHAR}
    and product_inner_code=#{productInnerCode,jdbcType=VARCHAR}
    and purchase_price=#{purchasePrice,jdbcType=DECIMAL}
    and purchase_number=#{purchaseNumber,jdbcType=NUMERIC}
    and pay_amount=#{payAmount,jdbcType=DECIMAL}
    and
        product_category_code=#{productCategoryCode,jdbcType=VARCHAR}


        and date_format(create_time,'%Y-%m')  =#{dateTime,jdbcType=VARCHAR}

    and apply_user_id=#{applyUserId,jdbcType=NUMERIC}
    and apply_user_name=#{applyUserName,jdbcType=VARCHAR}
    and task_num=#{taskNum,jdbcType=VARCHAR}
    and purchase_date=#{purchaseDate,jdbcType=VARCHAR}
    and
        apply_unit_code=#{applyUnitCode,jdbcType=VARCHAR}

    and
        apply_unit_name=#{applyUnitName,jdbcType=VARCHAR}

    and
        purchase_department=#{purchaseDepartment,jdbcType=VARCHAR}

    and
        report_account_time=#{reportAccountTime,jdbcType=VARCHAR}

    and invoice_urls=#{invoiceUrls,jdbcType=VARCHAR}
    and contract_urls=#{contractUrls,jdbcType=VARCHAR}
    and report_account_time is null
    and payment_voucher_urls is null
    and purchase_number>receive_number

order by id desc

select sum(pay_amount) from bms_order_detail_tb


        and product_inner_code=#{productInnerCode,jdbcType=VARCHAR}


        and product_category_code=#{productCategoryCode,jdbcType=VARCHAR}

    and
        apply_unit_code=#{applyUnitCode,jdbcType=VARCHAR}



            and date_format(create_time,'%Y') >=#{beginDateTime,jdbcType=VARCHAR}


            and date_format(create_time,'%Y') <=#{endDateTime,jdbcType=VARCHAR}




            and date_format(create_time,'%Y-%m') >=#{beginDateTime,jdbcType=VARCHAR}


            and date_format(create_time,'%Y-%m') <=#{endDateTime,jdbcType=VARCHAR}

