        and date_format(create_time,'%Y') <=#{endDateTime,jdbcType=VARCHAR}




        and date_format(create_time,'%Y-%m') >=#{beginDateTime,jdbcType=VARCHAR}


        and date_format(create_time,'%Y-%m') <=#{endDateTime,jdbcType=VARCHAR}

select
date_format(create_time,'%Y') as dateTime ,
date_format(create_time,'%Y-%m') as dateTime,
sum(pay_amount) as pay_amount
from bms_order_detail_tb


        and product_inner_code=#{productInnerCode,jdbcType=VARCHAR}


        and product_category_code=#{productCategoryCode,jdbcType=VARCHAR}

    and
        apply_unit_code=#{applyUnitCode,jdbcType=VARCHAR}



            and date_format(create_time,'%Y') >=#{beginDateTime,jdbcType=VARCHAR}


            and date_format(create_time,'%Y') <=#{endDateTime,jdbcType=VARCHAR}




            and date_format(create_time,'%Y-%m') >=#{beginDateTime,jdbcType=VARCHAR}


            and date_format(create_time,'%Y-%m') <=#{endDateTime,jdbcType=VARCHAR}



group by dateTime order by dateTime

select
SUBSTRING(report_account_time,1,4) as dateTime ,
report_account_time as dateTime,
sum(pay_amount) as pay_amount
from bms_order_detail_tb
where
report_account_time is not null

    and product_inner_code=#{productInnerCode,jdbcType=VARCHAR}


    and product_category_code=#{productCategoryCode,jdbcType=VARCHAR}

and
    apply_unit_code=#{applyUnitCode,jdbcType=VARCHAR}



        and SUBSTRING(report_account_time,1,4) >=#{beginDateTime,jdbcType=VARCHAR}


        and SUBSTRING(report_account_time,1,4) <=#{endDateTime,jdbcType=VARCHAR}




        and report_account_time >=#{beginDateTime,jdbcType=VARCHAR}


        and report_account_time <=#{endDateTime,jdbcType=VARCHAR}


group by dateTime order by dateTime

